package com.example.bank;

public class BankAccount {
    private double balance;          // only this class
    double transactionCount;         // package-private: same package
    protected String accountType;    // package + subclasses
    public final String accountId;   // everyone

    private static final double MAX_WITHDRAWAL = 10_000.0;

    public BankAccount(String id, String type, double initialBalance) {
        this.accountId = id;
        this.accountType = type;
        if (initialBalance < 0) throw new IllegalArgumentException("Initial balance cannot be negative");
        this.balance = initialBalance;
    }

    // Getter — controlled read access
    public double getBalance() { return balance; }

    // Methods enforce invariants
    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Deposit must be positive");
        balance += amount;
        transactionCount++;
    }

    public void withdraw(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Amount must be positive");
        if (amount > MAX_WITHDRAWAL) throw new IllegalArgumentException("Exceeds single withdrawal limit");
        if (amount > balance) throw new IllegalStateException("Insufficient funds");
        balance -= amount;
        transactionCount++;
    }

    // Tell, don't ask
    public boolean canAfford(double amount) {
        return balance >= amount;
    }

    @Override
    public String toString() {
        return accountId + ": $" + String.format("%.2f", balance);
    }
}

// In same package — can access package-private transactionCount
class AuditService {
    void audit(BankAccount acc) {
        System.out.println("Transactions: " + acc.transactionCount); // OK
        // System.out.println(acc.balance); // COMPILE ERROR — private
    }
}

