import java.time.LocalDate;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;

// Immutable: once created, state never changes
public final class ImmutableOrder {
    private final String orderId;
    private final LocalDate orderDate;
    private final List<String> items;  // mutable type — needs defense!
    private final double total;

    public ImmutableOrder(String orderId, LocalDate orderDate,
                          List<String> items, double total) {
        if (orderId == null || orderId.isBlank())
            throw new IllegalArgumentException("orderId required");
        if (total < 0)
            throw new IllegalArgumentException("total cannot be negative");

        this.orderId   = orderId;
        this.orderDate = orderDate;  // LocalDate is already immutable
        this.items     = List.copyOf(items); // DEFENSIVE COPY — unmodifiable
        this.total     = total;
    }

    public String getOrderId()    { return orderId; }
    public LocalDate getOrderDate() { return orderDate; }
    public double getTotal()      { return total; }

    // Return defensive copy — caller cannot modify internal list
    public List<String> getItems() {
        return Collections.unmodifiableList(items);
    }

    // 'With' methods return NEW instances instead of mutating
    public ImmutableOrder withTotal(double newTotal) {
        return new ImmutableOrder(orderId, orderDate, items, newTotal);
    }

    public ImmutableOrder addItem(String item) {
        List<String> newItems = new ArrayList<>(items);
        newItems.add(item);
        return new ImmutableOrder(orderId, orderDate, newItems, total);
    }

    @Override
    public String toString() {
        return orderId + "[" + items + "] $" + total;
    }

    public static void main(String[] args) {
        List<String> originalItems = new ArrayList<>();
        originalItems.add("Book");

        ImmutableOrder order = new ImmutableOrder("O001",
            LocalDate.of(2024, 1, 15), originalItems, 29.99);

        originalItems.add("Pen"); // Mutate the original list
        System.out.println(order.getItems()); // Still [Book] — defensive copy!

        ImmutableOrder updated = order.withTotal(35.99);
        System.out.println(order);   // unchanged
        System.out.println(updated); // new object with new total
    }
}

// Traditional JavaBean — mutable, verbose
public class PersonBean {
    private String firstName;
    private String lastName;
    private int age;

    public PersonBean() {}  // no-arg constructor required for frameworks

    public String getFirstName() { return firstName; }
    public void setFirstName(String firstName) {
        if (firstName == null || firstName.isBlank())
            throw new IllegalArgumentException("Name required");
        this.firstName = firstName;
    }

    public String getLastName() { return lastName; }
    public void setLastName(String lastName) { this.lastName = lastName; }

    public int getAge() { return age; }
    public void setAge(int age) {
        if (age < 0 || age > 150)
            throw new IllegalArgumentException("Invalid age: " + age);
        this.age = age;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof PersonBean)) return false;
        PersonBean p = (PersonBean) o;
        return age == p.age &&
               Objects.equals(firstName, p.firstName) &&
               Objects.equals(lastName, p.lastName);
    }

    @Override public int hashCode() { return Objects.hash(firstName, lastName, age); }
    @Override public String toString() { return firstName + " " + lastName + " (" + age + ")"; }
}

// Modern Record — immutable, concise (Java 16+)
public record PersonRecord(String firstName, String lastName, int age) {
    // Compact canonical constructor with validation
    public PersonRecord {
        if (firstName == null || firstName.isBlank())
            throw new IllegalArgumentException("Name required");
        if (age < 0 || age > 150)
            throw new IllegalArgumentException("Invalid age");
    }

    // Custom method
    public String fullName() { return firstName + " " + lastName; }

    // Derived field
    public boolean isAdult() { return age >= 18; }

    // equals, hashCode, toString auto-generated!
}

public class Demo {
    public static void main(String[] args) {
        // Bean
        PersonBean bean = new PersonBean();
        bean.setFirstName("Alice");
        bean.setLastName("Smith");
        bean.setAge(30);
        System.out.println(bean);

        // Record
        PersonRecord rec = new PersonRecord("Alice", "Smith", 30);
        System.out.println(rec);          // Alice Smith 30
        System.out.println(rec.fullName()); // Alice Smith
        System.out.println(rec.isAdult());  // true

        // Records are equal by VALUE
        PersonRecord rec2 = new PersonRecord("Alice", "Smith", 30);
        System.out.println(rec.equals(rec2)); // true
    }
}

