// BAD: leaks internal list reference
class BadStudentRoster {
    public List<String> students = new ArrayList<>(); // PUBLIC! exposed!

    public void enroll(String student) {
        students.add(student);
    }
}

// GOOD: properly encapsulated
class StudentRoster {
    private final List<String> students = new ArrayList<>();
    private final String courseId;
    private int maxCapacity;

    public StudentRoster(String courseId, int maxCapacity) {
        this.courseId = courseId;
        this.maxCapacity = maxCapacity;
    }

    public boolean enroll(String student) {
        if (students.size() >= maxCapacity) return false;
        if (students.contains(student)) return false; // already enrolled
        students.add(student);
        return true;
    }

    public boolean drop(String student) {
        return students.remove(student);
    }

    // Safe view — unmodifiable, no reference leakage
    public List<String> getStudents() {
        return Collections.unmodifiableList(students);
    }

    // Defensive copy — for when caller might sort/filter
    public List<String> getStudentsCopy() {
        return new ArrayList<>(students);
    }

    public int count() { return students.size(); }
    public boolean isFull() { return students.size() >= maxCapacity; }
    public boolean isEnrolled(String student) { return students.contains(student); }

    public String getCourseId() { return courseId; }

    @Override
    public String toString() {
        return courseId + ": " + students + " (" + students.size() + "/" + maxCapacity + ")";
    }

    public static void main(String[] args) {
        // BAD example
        BadStudentRoster bad = new BadStudentRoster();
        bad.students.add("Alice");
        bad.students.clear();   // External code can destroy the roster!
        bad.students = null;    // Or null it!

        // GOOD example
        StudentRoster roster = new StudentRoster("CS101", 3);
        roster.enroll("Alice");
        roster.enroll("Bob");

        List<String> view = roster.getStudents();
        // view.add("Hacker"); // Throws UnsupportedOperationException!

        System.out.println(roster);         // CS101: [Alice, Bob] (2/3)
        System.out.println(roster.isFull()); // false
    }
}

// Complex object with many optional parameters
// Without Builder: telescoping constructors or invalid intermediate state

public class HttpRequest {
    private final String method;    // required
    private final String url;       // required
    private final Map<String, String> headers;
    private final String body;
    private final int timeoutMs;
    private final boolean followRedirects;
    private final int maxRetries;

    // Private constructor — only Builder can create
    private HttpRequest(Builder builder) {
        this.method          = builder.method;
        this.url             = builder.url;
        this.headers         = Collections.unmodifiableMap(new HashMap<>(builder.headers));
        this.body            = builder.body;
        this.timeoutMs       = builder.timeoutMs;
        this.followRedirects = builder.followRedirects;
        this.maxRetries      = builder.maxRetries;
    }

    // Getters only
    public String getMethod()           { return method; }
    public String getUrl()              { return url; }
    public Map<String, String> getHeaders() { return headers; }
    public String getBody()             { return body; }
    public int getTimeoutMs()           { return timeoutMs; }
    public boolean isFollowRedirects()  { return followRedirects; }
    public int getMaxRetries()          { return maxRetries; }

    @Override
    public String toString() {
        return method + " " + url + " (timeout=" + timeoutMs + "ms)";
    }

    // Static nested Builder class
    public static class Builder {
        // Required
        private final String method;
        private final String url;
        // Optional — sensible defaults
        private Map<String, String> headers = new HashMap<>();
        private String body = null;
        private int timeoutMs = 5000;
        private boolean followRedirects = true;
        private int maxRetries = 3;

        public Builder(String method, String url) {
            if (method == null || url == null)
                throw new IllegalArgumentException("method and url required");
            this.method = method.toUpperCase();
            this.url    = url;
        }

        public Builder header(String key, String value) {
            headers.put(key, value);
            return this;
        }

        public Builder body(String body)                 { this.body = body; return this; }
        public Builder timeout(int ms)                   { this.timeoutMs = ms; return this; }
        public Builder followRedirects(boolean follow)   { this.followRedirects = follow; return this; }
        public Builder maxRetries(int n)                 { this.maxRetries = n; return this; }

        public HttpRequest build() {
            if ("POST".equals(method) || "PUT".equals(method)) {
                if (body == null) System.err.println("Warning: POST/PUT without body");
            }
            return new HttpRequest(this);
        }
    }

    public static void main(String[] args) {
        HttpRequest req = new HttpRequest.Builder("GET", "https://api.example.com/users")
            .header("Authorization", "Bearer token123")
            .header("Accept", "application/json")
            .timeout(3000)
            .maxRetries(5)
            .build();

        System.out.println(req);
        System.out.println(req.getHeaders());
    }
}

