// Accessibility rules:
// private (a):         only Base class
// package-private (b): com.app.model only
// protected (c):       com.app.model + subclasses (including com.app.service.Sub)
// public (d):          everywhere

class Solution {
    public Map<String, Boolean> checkAccess(String context) {
        Map<String, Boolean> map = new LinkedHashMap<>();
        switch (context) {
            case "same-class":
                map.put("a(private)", true);
                map.put("b(package)", true);
                map.put("c(protected)", true);
                map.put("d(public)", true);
                break;
            case "same-package":
                map.put("a(private)", false);
                map.put("b(package)", true);
                map.put("c(protected)", true);
                map.put("d(public)", true);
                break;
            case "subclass-diff-package":
                map.put("a(private)", false);
                map.put("b(package)", false);
                map.put("c(protected)", true);
                map.put("d(public)", true);
                break;
            case "unrelated-diff-package":
                map.put("a(private)", false);
                map.put("b(package)", false);
                map.put("c(protected)", false);
                map.put("d(public)", true);
                break;
        }
        return map;
    }
}

