public final class Temperature {
    private static final double ABSOLUTE_ZERO_C = -273.15;
    private final double celsius;

    private Temperature(double celsius) {
        if (celsius < ABSOLUTE_ZERO_C)
            throw new IllegalArgumentException("Below absolute zero: " + celsius);
        this.celsius = celsius;
    }

    public static Temperature celsius(double c)     { return new Temperature(c); }
    public static Temperature fahrenheit(double f)  { return new Temperature((f - 32) * 5.0/9); }
    public static Temperature kelvin(double k)      { return new Temperature(k - 273.15); }

    public double toCelsius()     { return celsius; }
    public double toFahrenheit()  { return celsius * 9.0/5 + 32; }
    public double toKelvin()      { return celsius + 273.15; }

    @Override
    public String toString() {
        return String.format("%.2f\u00b0C / %.2f\u00b0F / %.2fK",
            celsius, toFahrenheit(), toKelvin());
    }
}

