class ProductCatalog {
    private final Map<String, Product> catalog = new HashMap<>();

    public void addProduct(Product p) {
        if (p.getId() == null) throw new IllegalArgumentException();
        if (p.getPrice() <= 0) throw new IllegalArgumentException();
        catalog.put(p.getId(), p);
    }

    public Optional<Product> getProduct(String id) {
        return Optional.ofNullable(catalog.get(id));
    }

    public boolean removeProduct(String id) {
        return catalog.remove(id) != null;
    }

    public List<Product> listAll() {
        List<Product> sorted = new ArrayList<>(catalog.values());
        sorted.sort(Comparator.comparing(Product::getName));
        return Collections.unmodifiableList(sorted);
    }

    public List<Product> getSnapshot() {
        return catalog.values().stream()
            .map(Product::copy)
            .sorted(Comparator.comparing(Product::getName))
            .collect(Collectors.toList());
    }
}

