class ConfigManager {
    private final Map<String, String> config = new HashMap<>();
    private boolean locked = false;

    public void set(String key, String value) {
        if (locked) throw new IllegalStateException("Config is locked");
        config.put(key.toLowerCase(), value);
    }

    public void lock() { locked = true; }
    public boolean isLocked() { return locked; }

    public String get(String key) { return config.get(key.toLowerCase()); }

    public String getOrDefault(String key, String fallback) {
        return config.getOrDefault(key.toLowerCase(), fallback);
    }

    public String getRequired(String key) {
        String val = get(key);
        if (val == null) throw new java.util.NoSuchElementException("Missing config: " + key);
        return val;
    }

    public Map<String, String> getSnapshot() {
        return Collections.unmodifiableMap(new HashMap<>(config));
    }
}

