class BoundedPriorityQueue<T extends Comparable<T>> {
    private final PriorityQueue<T> pq;
    private final int capacity;

    public BoundedPriorityQueue(int capacity) {
        if (capacity <= 0) throw new IllegalArgumentException();
        this.capacity = capacity;
        this.pq = new PriorityQueue<>(); // min-heap
    }

    public boolean offer(T item) {
        if (pq.size() < capacity) {
            pq.offer(item);
            return true;
        }
        // Replace minimum if item is greater
        if (item.compareTo(pq.peek()) > 0) {
            pq.poll();
            pq.offer(item);
            return true;
        }
        return false;
    }

    public T poll() { return pq.poll(); }
    public T peek() { return pq.peek(); }
    public int size() { return pq.size(); }
    public boolean isFull() { return pq.size() >= capacity; }

    public List<T> snapshot() {
        List<T> list = new ArrayList<>(pq);
        Collections.sort(list);
        return Collections.unmodifiableList(list);
    }
}

