enum Role { USER, ADMIN, MODERATOR }

class UserRegistration {
    private final String username;
    private char[] password;
    private final String email;
    private Role role;

    public UserRegistration(String username, char[] password, String email, Role role) {
        validateUsername(username);
        validatePassword(password);
        validateEmail(email);
        this.username = username;
        this.password = Arrays.copyOf(password, password.length); // defensive copy!
        this.email    = email;
        this.role     = role != null ? role : Role.USER;
    }

    private static void validateUsername(String u) {
        if (u == null || !u.matches("[a-zA-Z0-9_]{3,20}"))
            throw new IllegalArgumentException("Invalid username: must be 3-20 alphanumeric/_");
    }

    private static void validatePassword(char[] p) {
        if (p == null || p.length < 8) throw new IllegalArgumentException("Password min 8 chars");
        String s = new String(p);
        if (!s.chars().anyMatch(Character::isUpperCase)) throw new IllegalArgumentException("Need uppercase");
