class EventLog {
    private final List<Event> events = new ArrayList<>();

    public void append(String type, String data) {
        if (type == null || type.isBlank()) throw new IllegalArgumentException("type required");
        events.add(new Event(Instant.now(), type, data));
    }

    public List<Event> getEvents() {
        return Collections.unmodifiableList(events);
    }

    public List<Event> getEventsByType(String type) {
        return events.stream()
            .filter(e -> type.equals(e.type()))
            .collect(Collectors.toUnmodifiableList());
    }

    public List<Event> getSince(Instant from) {
        return events.stream()
            .filter(e -> e.timestamp().isAfter(from))
            .collect(Collectors.toUnmodifiableList());
    }

    public int count() { return events.size(); }

    public Optional<Event> latestEvent() {
        return events.isEmpty() ? Optional.empty() :
               Optional.of(events.get(events.size() - 1));
    }
}

