interface Task { void run(); }

class Engine {
    private int rpm = 0;
    private static final int MAX_RPM = 8000;

    // 1. Static nested: can access static members, NOT instance members
    static class EngineSpec {
        int getMaxRpm() { return MAX_RPM; } // OK — static
        // int getActualRpm(Engine e) { return e.rpm; } // OK via reference, not directly
    }

    // 2. Inner class: HAS outer reference, can access private rpm
    class Diagnostics {
        void printRpm() { System.out.println("RPM: " + rpm); } // accesses outer private!
        void setRpm(int r) { rpm = Math.min(r, MAX_RPM); }     // writes outer private!
    }

    // 3. Local class: captures effectively-final local vars
    public Runnable createRevLimiter(int limit) {
        // limit must be effectively final
        class RevLimiter implements Runnable {
            @Override public void run() {
                if (rpm > limit) rpm = limit; // accesses outer private + captured limit
            }
        }
        return new RevLimiter();
    }

    // 4. Anonymous class
    public Runnable createIdleTask() {
        return new Runnable() {
            @Override public void run() {
                rpm = 800; // anonymous inner accesses outer private
            }
        };
    }

    public int getRpm() { return rpm; }

    public static void main(String[] args) {
        Engine engine = new Engine();
        Engine.Diagnostics diag = engine.new Diagnostics();
        diag.setRpm(3000);
        diag.printRpm(); // RPM: 3000

        engine.createIdleTask().run();
        System.out.println(engine.getRpm()); // 800

        System.out.println(new Engine.EngineSpec().getMaxRpm()); // 8000
    }
}

