               (surchargeApplied ? " [+surcharge]" : "");
    }

    public static class Builder {
        private String origin, destination;
        private LocalDate departureDate, returnDate;
        private int passengerCount = 1;
        private SeatClass seatClass = SeatClass.ECONOMY;
        private MealPref mealPref = MealPref.STANDARD;
        private boolean surcharge = false;

        public Builder(String origin, String dest, LocalDate departure) {
            if (origin==null||dest==null||departure==null) throw new IllegalArgumentException();
            this.origin=origin; this.destination=dest; this.departureDate=departure;
        }
        public Builder returnDate(LocalDate d)    { this.returnDate=d; return this; }
        public Builder passengers(int n)          { this.passengerCount=n; return this; }
