                throw new IllegalArgumentException("returnDate must be after departureDate");
            if (seatClass==SeatClass.FIRST && passengerCount>4)
                throw new IllegalArgumentException("FIRST class max 4 passengers");
            if (seatClass==SeatClass.FIRST && (mealPref==MealPref.VEGETARIAN||mealPref==MealPref.VEGAN))
                surcharge = true;
            return new FlightBooking(this);
        }
    }
}

