class LibraryBook {
    private final String isbn;
    private final String title;
    private final String author;
    private final int totalCopies;
    private int availableCopies;
    private final List<String> checkoutHistory = new ArrayList<>();
    private final Queue<String> waitlist = new LinkedList<>();

    public LibraryBook(String isbn, String title, String author, int copies) {
        if (!isbn.matches("\\d{3}-\\d{10}")) throw new IllegalArgumentException("Invalid ISBN: " + isbn);
        if (copies <= 0) throw new IllegalArgumentException("copies must be > 0");
        this.isbn = isbn; this.title = title; this.author = author;
        this.totalCopies = copies; this.availableCopies = copies;
    }

    public void checkout(String patronId) {
        if (availableCopies <= 0) throw new IllegalStateException("No copies available");
        availableCopies--;
        checkoutHistory.add(patronId + "@" + java.time.LocalDate.now());
    }

    public void returnBook() {
        if (availableCopies >= totalCopies) throw new IllegalStateException("All copies already in");
        availableCopies++;
    }

    public boolean reserve(String patronId) {
        if (availableCopies > 0) return false; // no need to reserve
        waitlist.offer(patronId);
        return true;
    }

    public boolean isAvailable()          { return availableCopies > 0; }
    public int waitlistSize()             { return waitlist.size(); }
    public String getIsbn()               { return isbn; }
    public String getTitle()              { return title; }
    public int getAvailableCopies()       { return availableCopies; }

    public List<String> getCheckoutHistory() {
        return Collections.unmodifiableList(checkoutHistory);
    }

    @Override
    public String toString() {
        return title + " [" + availableCopies + "/" + totalCopies + "] waitlist=" + waitlist.size();
    }
}

