class SafeClass {
    private int secret = 42;
    public int getSecret() { return secret; }
}

class Solution {
    public int readViaReflection(SafeClass obj) throws Exception {
        java.lang.reflect.Field f = SafeClass.class.getDeclaredField("secret");
        f.setAccessible(true); // bypasses private!
        return (int) f.get(obj); // reads private field
    }

    public void writeViaReflection(SafeClass obj, int newVal) throws Exception {
        java.lang.reflect.Field f = SafeClass.class.getDeclaredField("secret");
        f.setAccessible(true);
        f.set(obj, newVal); // writes private field!
    }

    public String explainDefenses() {
        return "Defenses against reflection:\n" +
               "1. Java 9+ modules: module-info.java with 'opens' limits setAccessible\n" +
               "2. final class: prevents reflective subclass attacks\n" +
               "3. Records: fields are final, reflection read works but write throws IllegalAccessException\n" +
               "4. SecurityManager (deprecated Java 17): install policy to deny ReflectPermission\n" +
               "5. Sealed classes: control inheritance, not reflection — partial defense";
    }
}

