class DatabaseConnectionPool {
    private static volatile DatabaseConnectionPool instance;
    private final List<String> available = new ArrayList<>();
    private final List<String> active    = new ArrayList<>();
    private final int maxSize;

    private DatabaseConnectionPool(int poolSize) {
        this.maxSize = poolSize;
        for (int i = 0; i < poolSize; i++)
            available.add("conn-" + i);
    }

    public static DatabaseConnectionPool getInstance() {
        if (instance == null) {                    // first check — no lock
            synchronized (DatabaseConnectionPool.class) {
                if (instance == null) {            // second check — with lock
                    instance = new DatabaseConnectionPool(10);
                }
            }
        }
        return instance;
    }

    public synchronized String getConnection() {
        if (available.isEmpty()) throw new IllegalStateException("Pool exhausted");
        String conn = available.remove(available.size() - 1);
        active.add(conn);
        return conn;
    }

    public synchronized void releaseConnection(String conn) {
        if (!active.remove(conn)) throw new IllegalArgumentException("Unknown connection: " + conn);
        available.add(conn);
    }

    public int getActiveCount() { return active.size(); }
    public int getPoolSize()    { return available.size() + active.size(); }

    // Package-private for testing
    static void resetForTesting() { instance = null; }
}

