class DirectedGraph<T> {
    private final Map<T, Set<T>> adjacency = new HashMap<>();

    public void addNode(T node) {
        adjacency.putIfAbsent(node, new HashSet<>());
    }

    public void removeNode(T node) {
        adjacency.remove(node);
        for (Set<T> neighbors : adjacency.values()) neighbors.remove(node);
    }

    public void addEdge(T from, T to) {
        if (!adjacency.containsKey(from)) throw new IllegalArgumentException("Node not found: " + from);
        if (!adjacency.containsKey(to))   throw new IllegalArgumentException("Node not found: " + to);
        if (from.equals(to)) throw new IllegalArgumentException("Self-loops not allowed");
        adjacency.get(from).add(to); // Set prevents duplicates
    }

    public void removeEdge(T from, T to) {
        Set<T> neighbors = adjacency.get(from);
        if (neighbors == null || !neighbors.remove(to))
            throw new IllegalArgumentException("Edge not found");
    }

    public Set<T> getNeighbors(T node) {
        Set<T> neighbors = adjacency.get(node);
        if (neighbors == null) throw new IllegalArgumentException("Node not found");
        return Collections.unmodifiableSet(neighbors);
    }

    public boolean hasPath(T from, T to) {
        if (!adjacency.containsKey(from) || !adjacency.containsKey(to)) return false;
        Set<T> visited = new HashSet<>();
        Queue<T> queue = new LinkedList<>();
        queue.offer(from);
        while (!queue.isEmpty()) {
            T curr = queue.poll();
            if (curr.equals(to)) return true;
            if (visited.add(curr))
                queue.addAll(adjacency.getOrDefault(curr, Collections.emptySet()));
        }
        return false;
    }

    public int nodeCount() { return adjacency.size(); }
}

