class MortgageApplication {
    private final double income, loanAmount, baseRate;
    private final int creditScore, termYears;
    private final double rateApplied;
    private final boolean approved;
    private final String rejectionReason;

    private MortgageApplication(Builder b) {
        this.income = b.income; this.loanAmount = b.loanAmount;
        this.baseRate = b.baseRate; this.creditScore = b.creditScore;
        this.termYears = b.termYears; this.rateApplied = b.rateApplied;
        this.approved = b.approved; this.rejectionReason = b.rejectionReason;
    }

    public boolean isApproved()       { return approved; }
    public double getRateApplied()    { return rateApplied; }
    public String getRejectionReason(){ return rejectionReason; }
    @Override public String toString() {
        return (approved ? "APPROVED" : "REJECTED") + " rate=" + rateApplied +
               (rejectionReason != null ? " reason=" + rejectionReason : "");
    }

    public static class Builder {
        private double income, loanAmount, baseRate = 5.0;
        private int creditScore, termYears;
        private double rateApplied;
        private boolean approved;
        private String rejectionReason;
        private List<String> errors = new ArrayList<>();

        public Builder income(double v)      { this.income = v; return this; }
        public Builder loanAmount(double v)  { this.loanAmount = v; return this; }
        public Builder creditScore(int v)    { this.creditScore = v; return this; }
        public Builder termYears(int v)      { this.termYears = v; return this; }
        public Builder baseRate(double v)    { this.baseRate = v; return this; }

        public MortgageApplication build() {
            // Layer 1: field validation
            if (income <= 0)     errors.add("income must be > 0");
            if (loanAmount <= 0) errors.add("loanAmount must be > 0");
            if (creditScore < 300 || creditScore > 850) errors.add("creditScore 300-850");
            if (!Set.of(10,15,20,30).contains(termYears)) errors.add("term must be 10/15/20/30 yrs");
            if (!errors.isEmpty()) throw new IllegalArgumentException(String.join("; ", errors));

            // Layer 2: ratio validation
            if (loanAmount > income * 10) {
                rejectionReason = "loanAmount exceeds 10x income";
                approved = false;
                rateApplied = baseRate;
                return new MortgageApplication(this);
            }
            double monthlyRate = baseRate / 100 / 12;
            int months = termYears * 12;
            double payment = loanAmount * (monthlyRate * Math.pow(1+monthlyRate,months)) /
                             (Math.pow(1+monthlyRate,months) - 1);
            if (payment > income / 12 * 0.43) {
                rejectionReason = "DTI ratio exceeds 43%";
                approved = false; rateApplied = baseRate;
                return new MortgageApplication(this);
            }

            // Layer 3: policy
            if (creditScore < 620 && loanAmount > 200_000) {
                rejectionReason = "credit < 620: max loan is 200,000";
                approved = false; rateApplied = baseRate;
                return new MortgageApplication(this);
            }
            rateApplied = creditScore >= 750 ? baseRate - 0.5 : baseRate;
            approved = true;
            return new MortgageApplication(this);
        }
    }
}

