import java.lang.reflect.*;

class EncapsulationReport {
    int publicFields, privateFields, getterCount, setterCount, score;
    boolean hasNoArgConstructor, hasFinalFields, hasEqualsHashCode;

    @Override public String toString() {
        return String.format("pubFields=%d privFields=%d getters=%d setters=%d " +
               "noArgCtor=%b finalFields=%b equalsHash=%b score=%d",
               publicFields, privateFields, getterCount, setterCount,
               hasNoArgConstructor, hasFinalFields, hasEqualsHashCode, score);
    }
}

class EncapsulationAuditor {
    public EncapsulationReport audit(Class<?> clazz) {
        EncapsulationReport r = new EncapsulationReport();

        for (Field f : clazz.getDeclaredFields()) {
            int mod = f.getModifiers();
            if (Modifier.isStatic(mod)) continue;
            if (Modifier.isPublic(mod)) r.publicFields++;
            else r.privateFields++;
            if (Modifier.isFinal(mod)) r.hasFinalFields = true;
        }

        for (Constructor<?> c : clazz.getDeclaredConstructors())
            if (c.getParameterCount() == 0) r.hasNoArgConstructor = true;

        boolean hasEquals = false, hasHash = false;
        for (Method m : clazz.getDeclaredMethods()) {
            String name = m.getName();
            if (name.startsWith("get") && m.getParameterCount()==0) r.getterCount++;
            else if (name.startsWith("set") && m.getParameterCount()==1) r.setterCount++;
            else if (name.equals("equals")   && m.getParameterCount()==1) hasEquals = true;
            else if (name.equals("hashCode") && m.getParameterCount()==0) hasHash  = true;
        }
        r.hasEqualsHashCode = (hasEquals == hasHash); // both or neither

        // Score
        int score = 50;
        score -= r.publicFields * 10;
        score += Math.min(r.privateFields * 5, 20);
        if (r.hasFinalFields)    score += 15;
        if (r.hasEqualsHashCode) score += 10;
        score -= r.setterCount * 3;
        r.score = Math.max(0, Math.min(100, score));
        return r;
    }
}
